module decoder_3to8(
    input  [2:0] a,
    output [7:0] y
);

reg [7:0] z_out;

always @(*) begin
    case (a)
        3'b000: z_out = 8'b00000001;
        3'b001: z_out = 8'b00000010;
        3'b010: z_out = 8'b00000100;
        3'b011: z_out = 8'b00001000;
        3'b100: z_out = 8'b00010000;
        3'b101: z_out = 8'b00100000;
        3'b110: z_out = 8'b01000000;
        3'b111: z_out = 8'b10000000;
        default: z_out = 8'b00000000;
    endcase
end

assign y = z_out;

endmodule
